   219→          : undefined,
   220→        paymentType: firstPayment
   221→          ? getPaymentTypeLabel(firstPayment.paymentType)
   222→          : undefined,
   223→        shippingValuePoints:
   224→          marketplace.shippingValuePoints !== undefined &&
   225→          marketplace.shippingValuePoints !== null
   226→            ? getFormattedPointsValueForMarketplace(
   227→                marketplace.shippingValuePoints,
   228→              )
   229→            : undefined,
   230→        valuePoints:
   231→          marketplace.valuePoints !== undefined &&
   232→          marketplace.valuePoints !== null
   233→            ? getFormattedPointsValueForMarketplace(marketplace.valuePoints)
   234→            : undefined,
